一、获取基本信息NSString *deviceName = [self getDeviceName]; // 这个方法后面会列出来NSLog(@&quot;设备型号--&gt;%@&quot;, deviceName);NSString *iPhoneName = [UIDevice currentDevice].name;NSLog(@&quot;iPhone名称--&gt;%@&quot;, iPhoneName); NSString *appVerion = [[[NSBundle mainBundle] infoDictionary] objectForKey:@&quot;CFBundleShortVersionString&quot;];NSLog(@&quot;app版本号--&gt;%@&quot;, appVerion);CGFloat batteryLevel = [[UIDevice currentDevice] batteryLevel];NSLog(@&quot;电池电量--&gt;%f&quot;, batteryLevel);NSString *localizedModel = [UIDevice currentDevice].localizedModel;NSLog(@&quot;localizedModel--&gt;%@&quot;, localizedModel);NSString *systemName = [UIDevice currentDevice].systemName;NSLog(@&quot;当前系统名称--&gt;%@&quot;, systemName);NSString *systemVersion = [UIDevice currentDevice].systemVersion;NSLog(@&quot;当前系统版本号--&gt;%@&quot;, systemVersion);struct utsname systemInfo;uname(&amp;systemInfo);NSString *device_model = [NSString stringWithCString:systemInfo.machine encoding:NSUTF8StringEncoding];NSLog(@&quot;device_model--&gt;%@&quot;, device_model);NSString *macAddress = [self getMacAddress];// 这个方法后面会单独列出NSLog(@&quot;macAddress--&gt;%@&quot;, macAddress);NSString *deviceIP = [self getDeviceIPAddresses];// 这个方法后面会单独列出NSLog(@&quot;deviceIP--&gt;%@&quot;, deviceIP);

1.1、设备上次重启的时间NSTimeInterval time = [[NSProcessInfo processInfo] systemUptime];NSDate *lastRestartDate = [[NSDate alloc] initWithTimeIntervalSinceNow:(0 - time)];
广告位标识符：在同一个设备上的所有App都会取到相同的值，是苹果专门给各广告提供商用来追踪用户而设的，用户可以在 设置|隐私|广告追踪里重置此id的值，或限制此id的使用，故此id有可能会取不到值，但好在Apple默认是允许追踪的，而且一般用户都不知道有这么个设置，所以基本上用来监测推广效果，是绰绰有余了
NSString *idfa = [[[ASIdentifierManager sharedManager] advertisingIdentifier] UUIDString];NSLog(@&quot;广告位标识符idfa--&gt;%@&quot;, idfa);
UUID是Universally Unique Identifier的缩写，中文意思是通用唯一识别码。它是让分布式系统中的所有元素，都能有唯一的辨识资讯，而不需要透过中央控制端来做辨识资讯的指 定。这样，每个人都可以建立不与其它人冲突的 UUID。在此情况下，就不需考虑数据库建立时的名称重复问题。苹果公司建议使用UUID为应用生成唯一标识字符串。
NSString *uuid = [[[UIDevice currentDevice] identifierForVendor] UUIDString];NSLog(@&quot;唯一识别码uuid--&gt;%@&quot;, uuid);
