uot;;    if ([deviceString isEqualToString:@&quot;iPhone9,3&quot;])    return @&quot;美版、台版iPhone 7&quot;;    if ([deviceString isEqualToString:@&quot;iPhone9,4&quot;])    return @&quot;美版、台版iPhone 7 Plus&quot;;    if ([deviceString isEqualToString:@&quot;iPhone10,1&quot;])   return @&quot;国行(A1863)、日行(A1906)iPhone 8&quot;;    if ([deviceString isEqualToString:@&quot;iPhone10,4&quot;])   return @&quot;美版(Global/A1905)iPhone 8&quot;;    if ([deviceString isEqualToString:@&quot;iPhone10,2&quot;])   return @&quot;国行(A1864)、日行(A1898)iPhone 8 Plus&quot;;    if ([deviceString isEqualToString:@&quot;iPhone10,5&quot;])   return @&quot;美版(Global/A1897)iPhone 8 Plus&quot;;    if ([deviceString isEqualToString:@&quot;iPhone10,3&quot;])   return @&quot;国行(A1865)、日行(A1902)iPhone X&quot;;    if ([deviceString isEqualToString:@&quot;iPhone10,6&quot;])   return @&quot;美版(Global/A1901)iPhone X&quot;;         if ([deviceString isEqualToString:@&quot;iPod1,1&quot;])      return @&quot;iPod Touch 1G&quot;;    if ([deviceString isEqualToString:@&quot;iPod2,1&quot;])      return @&quot;iPod Touch 2G&quot;;    if ([deviceString isEqualToString:@&quot;iPod3,1&quot;])      return @&quot;iPod Touch 3G&quot;;    if ([deviceString isEqualToString:@&quot;iPod4,1&quot;])      return @&quot;iPod Touch 4G&quot;;    if ([deviceString isEqualToString:@&quot;iPod5,1&quot;])      return @&quot;iPod Touch (5 Gen)&quot;;         if ([deviceString isEqualToString:@&quot;iPad1,1&quot;])      return @&quot;iPad&quot;;    if ([deviceString isEqualToString:@&quot;iPad1,2&quot;])      return @&quot;iPad 3G&quot;;    if ([deviceString isEqualToString:@&quot;iPad2,1&quot;])      return @&quot;iPad 2 (WiFi)&quot;;    if ([deviceString isEqualToString:@&quot;iPad2,2&quot;])      return @&quot;iPad 2&quot;;    if ([deviceString isEqualToString:@&quot;iPad2,3&quot;])      return @&quot;iPad 2 (CDMA)&quot;;    if ([deviceString isEqualToString:@&quot;iPad2,4&quot;])      return @&quot;iPad 2&quot;;    if ([deviceString isEqualToString:@&quot;iPad2,5&quot;])      return @&quot;iPad Mini (WiFi)&quot;;    if ([deviceString isEqualToString:@&quot;iPad2,6&quot;])      return @&quot;iPad Mini&quot;;    if ([deviceString isEqualToString:@&quot;iPad2,7&quot;])      return @&quot;iPad Mini (GSM+CDMA)&quot;;    if ([deviceString isEqualToString:@&quot;iPad3,1&quot;])      return @&quot;iPad 3 (WiFi)&quot;;    if ([deviceString isEqualToString:@&quot;iPad3,2&quot;])      return @&quot;iPad 3 (GSM+CDMA)&quot;;    if ([deviceString isEqualToString:@&quot;iPad3,3&quot;])      return @&quot;iPad 3&quot;;    if ([deviceString isEqualToString:@&quot;iPad3,4&quot;])      return @&quot;iPad 4 (WiFi)&quot;;    if ([deviceString isEqualToString:@&quot;iPad3,5&quot;])      return @&quot;iPad 4&quot;;    if ([deviceString isEqualToString:@&quot;iPad3,6&quot;])      return @&quot;iPad 4 (GSM+CDMA)&quot;;    if ([deviceString isEqualToString:@&quot;iPad4,1&quot;])      return @&quot;iPad Air (WiFi)&quot;;    if ([deviceString isEqualToString:@&quot;iPad4,2&quot;])      return @&quot;iPad Air (Cellular)&quot;;    if ([deviceString isEqualToString:@&quot;iPad4,4&quot;])      return @&quot;iPad Mini 2 (WiFi)&quot;;    if ([deviceString isEqualToString:@&quot;iPad4,5&quot;])      return @&quot;iPad Mini 2 (Cellular)&quot;;    if ([deviceString isEqualToString:@&quot;iPad4,6&quot;])      return @&quot;iPad Mini 2&quot;;    if ([deviceString isEqualToString:@&quot;iPad4,7&quot;])      return @&quot;iPad Mini 3&quot;;    if ([deviceString isEqualToString:@&quot;iPad4,8&quot;])      return @&quot;iPad Mini 3&quot;;    if ([deviceString isEqualToString:@&quot;iPad4,9&quot;])      return @&quot;iPad Mini 3&quot;;    if ([deviceString isEqualToString:@&quot;iPad5,1&quot;])      return @&quot;iPad Mini 4 (WiFi)&quot;;    if ([deviceString isEqualToString:@&quot;iPad5,2&quot;])      return @&quot;iPad Mini 4 (LTE)&quot;;    if ([deviceString isEqualToString:@&quot;iPad5,3&quot;])      return @&quot;iPad Air 2&quot;;    if ([deviceString isEqualToString:@&quot;iPad5,4&quot;])      return @&quot;iPad Air 2&quot;;    if ([deviceString isEqualToString:@&quot;iPad6,3&quot;])      return @&quot;iPad Pro 9.7&quot;;    if ([deviceString isEqualToString:@&quot;iPad6,4&quot;])      return @&quot;iPad Pro 9.7&quot;;    if ([deviceString isEqualToString:@&quot;iPad6,7&quot;])      return @&quot;iPad Pro 12.9&quot;;    if ([deviceString isEqualToString:@&quot;iPad6,8&quot;])      return @&quot;iPad Pro 12.9&quot;;    if ([machineString isEqualToString:@&quot;iPad6,11&quot;])    return @&quot;iPad 5 (WiFi)&quot;;    if ([machineString isEqualToString:@&quot;iPad6,12&quot;])    return @&quot;iPad 5 (Cellular)&quot;;    if ([machineString isEqualToString:@&quot;iPad7,1&quot;])     return @&quot;iPad Pro 12.9 inch 2nd gen (WiFi)&quot;;    if ([machineString isEqualToString:@&quot;iPad7,2&quot;])     return @&quot;iPad Pro 12.9 inch 2nd gen (Cellular)&quot;;    if ([machineString isEqualToString:@&quot;iPad7,3&quot;])     return @&quot;iPad Pro 10.5 inch (WiFi)&quot;;    if ([machineString isEqualToString:@&quot;iPad7,4&quot;])     return @&quot;iPad Pro 10.5 inch (Cellular)&quot;;        if ([deviceString isEqualToString:@&quot;AppleTV2,1&quot;])    return @&quot;Apple TV 2&quot;;   if ([deviceString isEqualToString:@&quot;AppleTV3,1&quot;])    return @&quot;Apple TV 3&quot;;   if ([deviceString isEqualToString:@&quot;AppleTV3,2&quot;])    return @&quot;Apple TV 3&quot;;   if ([deviceString isEqualToString:@&quot;AppleTV5,3&quot;])    return @&quot;Apple TV 4&quot;;     if ([deviceString isEqualToString:@&quot;i386&quot;])         return @&quot;Simulator&quot;;    if ([deviceString isEqualToString:@&quot;x86_64&quot;])       return @&quot;Simulator&quot;;         return deviceString;&#125;
二、mac 地址- (NSString *)getMacAddress &#123;    int mib[6];    size_t len;    char *buf;    unsigned char *ptr;    struct if_msghdr *ifm;    struct sockaddr_dl *sdl;         mib[0] = CTL_NET;    mib[1] = AF_ROUTE;    mib[2] = 0;    mib[3] = AF_LINK;    mib[4] = NET_RT_IFLIST;         if ((mib[5] = if_nametoindex(&quot;en0&quot;)) == 0) &#123;        printf(&quot;Error: if_nametoindex error/n&quot;);        return NULL;    &#125;         if (sysctl(mib, 6, NULL, &amp;len, NULL, 0) &lt; 0) &#123;        printf(&quot;Error: sysctl, take 1/n&quot;);        return NULL;    &#125;         if ((buf = malloc(len)) == NULL) &#123;        printf(&quot;Could not allocate memory. error!/n&quot;);        return NULL;    &#125;         if (sysctl(mib, 6, buf, &amp;len, NULL, 0) &lt; 0) &#123;        printf(&quot;Error: sysctl, take 2&quot;);        return NULL;    &#125;         ifm = (struct if_msghdr *)buf;    sdl = (struct sockaddr_dl *)(ifm + 1);    ptr = (unsigned char *)LLADDR(sdl);         NSString *outstring = [NSString stringWithFormat:@&quot;xxxxxx&quot;, *ptr, *(ptr+1), *(ptr+2), *(ptr+3), *(ptr+4), *(ptr+5)];    free(buf);         return [outstring uppercaseString];&#125;

三、IP地址- (NSString *)getDeviceIPAddresses &#123;         int sockfd = socket(AF_INET, SOCK_DGRAM, 0);         NSMutableArray *ips = [NSMutableArray array];         int BUFFERSIZE = 4096;         struct ifconf ifc;         char buffer[BUFFERSIZE], *ptr, lastname[IFNAMSIZ], *cptr;         struct ifreq *ifr, ifrcopy;         ifc.ifc_len = BUFFERSIZE;    ifc.ifc_buf = buffer;         if (ioctl(sockfd, SIOCGIFCONF, &amp;ifc) &gt;= 0)&#123;                 for (ptr = buffer; ptr &lt; buffer + ifc.ifc_len; )&#123;                         ifr = (struct ifreq *)ptr;            int len = sizeof(struct sockaddr);                         if (ifr-&gt;ifr_addr.sa_len &gt; len) &#123;                len = ifr-&gt;ifr_addr.sa_len;            &#125;                         ptr += sizeof(ifr-&gt;ifr_name) + len;            if (ifr-&gt;ifr_addr.sa_family != AF_INET) continue;            if ((cptr = (char *)strchr(ifr-&gt;ifr_name, &#x27;:&#x27;)) != NULL) *cptr = 0;            if (strncmp(lastname, ifr-&gt;ifr_name, IFNAMSIZ) == 0) continue;                         memcpy(lastname, ifr-&gt;ifr_name, IFNAMSIZ);            ifrcopy = *ifr;            ioctl(sockfd, SIOCGIFFLAGS, &amp;ifrcopy);                         if ((ifrcopy.ifr_flags &amp; IFF_UP) == 0) continue;                         NSString *ip = [NSString  stringWithFormat:@&quot;%s&quot;, inet_ntoa(((struct sockaddr_in *)&amp;ifr-&gt;ifr_addr)-&gt;sin_addr)];            [ips addObject:ip];        &#125;    &#125;         close(sockfd);    NSString *deviceIP = @&quot;&quot;;         for (int i=0; i &lt; ips.count; i++) &#123;        if (ips.count &gt; 0) &#123;            deviceIP = [NSString stringWithFormat:@&quot;%@&quot;,ips.lastObject];        &#125;    &#125;    return deviceIP;&#125;

四、CPU4.1、CPU总数目- (NSUInteger)getCPUCount &#123;    return [NSProcessInfo processInfo].activeProcessorCount;&#125;
4.2、已使用的CPU比例- (float)getCPUUsage &#123;    float cpu = 0;    NSArray *cpus = [self getPerCPUUsage];    if (cpus.count == 0) return -1;    for (NSNumber *n in cpus) &#123;        cpu += n.floatValue;    &#125;    return cpu;&#125;
4.3、获取每个cpu的使用比例- (NSArray *)getPerCPUUsage &#123;    processor_info_array_t _cpuInfo, _prevCPUInfo = nil;    mach_msg_type_number_t _numCPUInfo, _numPrevCPUInfo = 0;    unsigned _numCPUs;    NSLock *_cpuUsageLock;         int _mib[2U] = &#123; CTL_HW, HW_NCPU &#125;;    size_t _sizeOfNumCPUs = sizeof(_numCPUs);    int _status = sysctl(_mib, 2U, &amp;_numCPUs, &amp;_sizeOfNumCPUs, NULL, 0U);    if (_status)        _numCPUs = 1;         _cpuUsageLock = [[NSLock alloc] init];         natural_t _numCPUsU = 0U;    kern_return_t err = host_processor_info(mach_host_self(), PROCESSOR_CPU_LOAD_INFO, &amp;_numCPUsU, &amp;_cpuInfo, &amp;_numCPUInfo);    if (err == KERN_SUCCESS) &#123;        [_cpuUsageLock lock];                 NSMutableArray *cpus = [NSMutableArray new];        for (unsigned i = 0U; i &lt; _numCPUs; ++i) &#123;            Float32 _inUse, _total;            if (_prevCPUInfo) &#123;                _inUse = (                          (_cpuInfo[(CPU_STATE_MAX * i) + CPU_STATE_USER]   - _prevCPUInfo[(CPU_STATE_MAX * i) + CPU_STATE_USER])                          + (_cpuInfo[(CPU_STATE_MAX * i) + CPU_STATE_SYSTEM] - _prevCPUInfo[(CPU_STATE_MAX * i) + CPU_STATE_SYSTEM])                          + (_cpuInfo[(CPU_STATE_MAX * i) + CPU_STATE_NICE]   - _prevCPUInfo[(CPU_STATE_MAX * i) + CPU_STATE_NICE])                          );                _total = _inUse + (_cpuInfo[(CPU_STATE_MAX * i) + CPU_STATE_IDLE] - _prevCPUInfo[(CPU_STATE_MAX * i) + CPU_STATE_IDLE]);            &#125; else &#123;                _inUse = _cpuInfo[(CPU_STATE_MAX * i) + CPU_STATE_USER] + _cpuInfo[(CPU_STATE_MAX * i) + CPU_STATE_SYSTEM] + _cpuInfo[(CPU_STATE_MAX * i) + CPU_STATE_NICE];                _total = _inUse + _cpuInfo[(CPU_STATE_MAX * i) + CPU_STATE_IDLE];            &#125;            [cpus addObject:@(_inUse / _total)];        &#125;                 [_cpuUsageLock unlock];        if (_prevCPUInfo) &#123;            size_t prevCpuInfoSize = sizeof(integer_t) * _numPrevCPUInfo;            vm_deallocate(mach_task_self(), (vm_address_t)_prevCPUInfo, prevCpuInfoSize);        &#125;        return cpus;    &#125; else &#123;        return nil;    &#125;&#125;
五、Disk磁盘空间5.1、获取磁盘总空间- (int64_t)getTotalDiskSpace &#123;    NSError *error = nil;    NSDictionary *attrs = [[NSFileManager defaultManager] attributesOfFileSystemForPath:NSHomeDirectory() error:&amp;error];    if (error) return -1;    int64_t space =  [[attrs objectForKey:NSFileSystemSize] longLongValue];    if (space &lt; 0) space = -1;    return space;&#125;
5.2、获取未使用的磁盘空间- (int64_t)getFreeDiskSpace &#123;    NSError *error = nil;    NSDictionary *attrs = [[NSFileManager defaultManager] attributesOfFileSystemForPath:NSHomeDirectory() error:&amp;error];    if (error) return -1;    int64_t space =  [[attrs objectForKey:NSFileSystemFreeSize] longLongValue];    if (space &lt; 0) space = -1;    return space;&#125;
5.3、获取已使用的磁盘空间- (int64_t)getUsedDiskSpace &#123;    int64_t totalDisk = [self getTotalDiskSpace];    int64_t freeDisk = [self getFreeDiskSpace];    if (totalDisk &lt; 0 || freeDisk &lt; 0) return -1;    int64_t usedDisk = totalDisk - freeDisk;    if (usedDisk &lt; 0) usedDisk = -1;    return usedDisk;&#125;
六、Memory内存相关数据6.1、系统总内存空间- (int64_t)getTotalMemory &#123;    int64_t totalMemory = [[NSProcessInfo processInfo] physicalMemory];    if (totalMemory &lt; -1) totalMemory = -1;    return totalMemory;&#125;
6.2、活跃的内存,正在使用或者很短时间内被使用过- (int64_t)getActiveMemory &#123;    mach_port_t host_port = mach_host_self();    mach_msg_type_number_t host_size = sizeof(vm_statistics_data_t) / sizeof(integer_t);    vm_size_t page_size;    vm_statistics_data_t vm_stat;    kern_return_t kern;    5    kern = host_page_size(host_port, &amp;page_size);    if (kern != KERN_SUCCESS) return -1;    kern = host_statistics(host_port, HOST_VM_INFO, (host_info_t)&amp;vm_stat, &amp;host_size);    if (kern != KERN_SUCCESS) return -1;    return vm_stat.active_count * page_size;&#125;
6.3、最近使用过,但是目前处于不活跃状态的内存- (int64_t)getInActiveMemory &#123;    mach_port_t host_port = mach_host_self();    mach_msg_type_number_t host_size = sizeof(vm_statistics_data_t) / sizeof(integer_t);    vm_size_t page_size;    vm_statistics_data_t vm_stat;    kern_return_t kern;    5    kern = host_page_size(host_port, &amp;page_size);    if (kern != KERN_SUCCESS) return -1;    kern = host_statistics(host_port, HOST_VM_INFO, (host_info_t)&amp;vm_stat, &amp;host_size);    if (kern != KERN_SUCCESS) return -1;    return vm_stat.inactive_count * page_size;&#125;
6.4、空闲的内存空间- (int64_t)getFreeMemory &#123;    mach_port_t host_port = mach_host_self();    mach_msg_type_number_t host_size = sizeof(vm_statistics_data_t) / sizeof(integer_t);    vm_size_t page_size;    vm_statistics_data_t vm_stat;    kern_return_t kern;    5    kern = host_page_size(host_port, &amp;page_size);    if (kern != KERN_SUCCESS) return -1;    kern = host_statistics(host_port, HOST_VM_INFO, (host_info_t)&amp;vm_stat, &amp;host_size);    if (kern != KERN_SUCCESS) return -1;    return vm_stat.free_count * page_size;&#125;
6.5、已使用的内存空间- (int64_t)getUsedMemory &#123;    mach_port_t host_port = mach_host_self();    mach_msg_type_number_t host_size = sizeof(vm_statistics_data_t) / sizeof(integer_t);    vm_size_t page_size;    vm_statistics_data_t vm_stat;    kern_return_t kern;    5    kern = host_page_size(host_port, &amp;page_size);    if (kern != KERN_SUCCESS) return -1;    kern = host_statistics(host_port, HOST_VM_INFO, (host_info_t)&amp;vm_stat, &amp;host_size);    if (kern != KERN_SUCCESS) return -1;    return page_size * (vm_stat.active_count + vm_stat.inactive_count + vm_stat.wire_count);&#125;
6.6、用来存放内核和数据结构的内存,framework、用户级别的应用无法分配- (int64_t)getWiredMemory &#123;    mach_port_t host_port = mach_host_self();    mach_msg_type_number_t host_size = sizeof(vm_statistics_data_t) / sizeof(integer_t);    vm_size_t page_size;    vm_statistics_data_t vm_stat;    kern_return_t kern;    5    kern = host_page_size(host_port, &amp;page_size);    if (kern != KERN_SUCCESS) return -1;    kern = host_statistics(host_port, HOST_VM_INFO, (host_info_t)&amp;vm_stat, &amp;host_size);    if (kern != KERN_SUCCESS) return -1;    return vm_stat.wire_count * page_size;&#125;
6.7、可释放的内存空间：内存吃紧自动释放，针对大对象存放所需的大块内存空间- (int64_t)getPurgableMemory &#123;    mach_port_t host_port = mach_host_self();    mach_msg_type_number_t host_size = sizeof(vm_statistics_data_t) / sizeof(integer_t);    vm_size_t page_size;    vm_statistics_data_t vm_stat;    kern_return_t kern;    5    kern = host_page_size(host_port, &amp;page_size);    if (kern != KERN_SUCCESS) return -1;    kern = host_statistics(host_port, HOST_VM_INFO, (host_info_t)&amp;vm_stat, &amp;host_size);    if (kern != KERN_SUCCESS) return -1;    return vm_stat.purgeable_count * page_size;&#125;

