二、在生成的.cpp源码中查看FLYPerson类既然我们探究的是类，那就是Class，我们在cpp文件中可以看到：
typedef struct objc_class * Class;
这说明，Class其实就是objc_class结构体的指针继续查找，可以发现objc_clss的声明：
struct objc_class &#123;    Class _Nonnull isa __attribute__((deprecated));&#125; __attribute__((unavailable));
已经注释已经废弃，没有办法了么？还记得我们已经准备好了756的源码，去源码中搜索objc_class，会发现几点重要信息：上图中可以证实，class其实就是objc_class

三、分析objc_class源码1、先来了解一下主要的数据结构看一下objc_class数据结构：objc-runtime-new.h中struct objc_class : objc_object
struct objc_class : objc_object &#123;    // Class ISA;    Class superclass;    cache_t cache;             // formerly cache pointer and vtable    class_data_bits_t bits;    // class_rw_t * plus custom rr/alloc flags    ...//此处省略了结构体内的函数方法，以上是全部属性&#125;

看一下内部属性的各自数据结构，这里的&#x2F;&#x2F; Class ISA; ISA被隐藏了，这是因为objc_class继承自objc_object
struct objc_object &#123;    Class _Nonnull isa  OBJC_ISA_AVAILABILITY;&#125;;
注意：这里isa用Class类型，应该是与oc的多态类似，isa和class的结构相同，或者isa就是按照class的结构来设计的。
cache_t：（对sel和imp做缓存，这里有一个3&#x2F;4缓存机制）
struct cache_t &#123;    struct bucket_t *_buckets; // 指针占用8字节    mask_t _mask;              // uint32_t类型 32 / 8 = 4字节    mask_t _occupied;          // uint32_t类型 32 / 8 = 4字节    ... //省略所有函数方法&#125;
class_data_bits_t：（这里只有一个属性bits,其中具体的值要转换成data查看，即class_rw_t* data() ）
struct class_data_bits_t &#123;    // Values are the FAST_ flags above.    uintptr_t bits;private:    ...public:    class_rw_t* data() &#123;        return (class_rw_t *)(bits &amp; FAST_DATA_MASK);    &#125;    void setData(class_rw_t *newData)    &#123;        assert(!data()  ||  (newData-&gt;flags &amp; (RW_REALIZING | RW_FUTURE)));        // Set during realization or construction only. No locking needed.        // Use a store-release fence because there may be concurrent        // readers of data and data&#x27;s contents.        uintptr_t newBits = (bits &amp; ~FAST_DATA_MASK) | (uintptr_t)newData;        atomic_thread_fence(memory_order_release);        bits = newBits;    &#125;    ...//以下函数省略&#125;
class_rw_t的数据结构：
struct class_rw_t &#123;    // Be warned that Symbolication knows the layout of this structure.    uint32_t flags;    uint32_t version;    const class_ro_t *ro;    method_array_t methods;    property_array_t properties;    protocol_array_t protocols;    Class firstSubclass;    Class nextSiblingClass;    char *demangledName;#if SUPPORT_INDEXED_ISA    uint32_t index;#endif    void setFlags(uint32_t set)     &#123;        OSAtomicOr32Barrier(set, &amp;flags);    &#125;    void clearFlags(uint32_t clear)     &#123;        OSAtomicXor32Barrier(clear, &amp;flags);    &#125;    // set and clear must not overlap    void changeFlags(uint32_t set, uint32_t clear)     &#123;        assert((set &amp; clear) == 0);        uint32_t oldf, newf;        do &#123;            oldf = flags;            newf = (oldf | set) &amp; ~clear;        &#125; while (!OSAtomicCompareAndSwap32Barrier(oldf, newf, (volatile int32_t *)&amp;flags));    &#125;&#125;;
class_ro_t的数据结构：
struct class_ro_t &#123;    uint32_t flags;    uint32_t instanceStart;    uint32_t instanceSize;#ifdef __LP64__    uint32_t reserved;#endif    const uint8_t * ivarLayout;        const char * name;    method_list_t * baseMethodList;    protocol_list_t * baseProtocols;    const ivar_list_t * ivars;    const uint8_t * weakIvarLayout;    property_list_t *baseProperties;    method_list_t *baseMethods() const &#123;        return baseMethodList;    &#125;&#125;;
