4、探索cache的原理看一下cache_t完整的结构体
struct cache_t &#123;    struct bucket_t *_buckets; //实际存储区     mask_t _mask;     // 当前容量    mask_t _occupied; // 当前占据public:    struct bucket_t *buckets();    mask_t mask();    mask_t occupied();    void incrementOccupied();    void setBucketsAndMask(struct bucket_t *newBuckets, mask_t newMask);    void initializeToEmpty();    mask_t capacity();    bool isConstantEmptyCache();    bool canBeFreed();    static size_t bytesForCapacity(uint32_t cap);    static struct bucket_t * endMarker(struct bucket_t *b, uint32_t cap);    void expand();    void reallocate(mask_t oldCapacity, mask_t newCapacity);    struct bucket_t * find(cache_key_t key, id receiver);    static void bad_cache(id receiver, SEL sel, Class isa) __attribute__((noreturn));&#125;;
bucket_t的结构：
struct bucket_t &#123;private:    // IMP-first is better for arm64e ptrauth and no worse for arm64.    // SEL-first is better for armv7* and i386 and x86_64.#if __arm64__    MethodCacheIMP _imp;    cache_key_t _key;#else    cache_key_t _key;    MethodCacheIMP _imp;#endifpublic:    inline cache_key_t key() const &#123; return _key; &#125;    inline IMP imp() const &#123; return (IMP)_imp; &#125;    inline void setKey(cache_key_t newKey) &#123; _key = newKey; &#125;    inline void setImp(IMP newImp) &#123; _imp = newImp; &#125;    void set(cache_key_t newKey, IMP newImp);&#125;;
可见，sel和imp都是存在bucket_t中。跑一下项目，将断点打在[person sayGoGo]，利用lldb查看内存
