一、runtime定义 : 一套由c、c++和汇编编写能够为oc提供运行时功能的api。runtime有两个版本，分别是modern’ 和 ‘legacy’， legacy是老版本中的runtime，Objective-C 2.0 以及后续版本中用的都是modern版本的runtime（参考官方文档）。
使用方式可以归纳为三种：1、Objective-C code @selector()2、NSObject的方法    NSSelectorFromString()3、sel_registerName 函数api
一、objc_msgSend首先，objc_msgSend是用汇编写的，那么为什么会选用汇编写呢？原因有如下两点

1、因为在C语言中不可能通过写一个函数来保留未知的参数并且跳转到一个任意的函数指针。C语言没有足够做这件事的必要特性。
2、因为objc_msgSend执行的频率是想当非常之高，所以必须保证执行的足够快，这里汇编也就必然是首选。

objc_msgSend可以分为快速路径，慢速路径，都是用C实现的。
作用流程：1：ENTRY _objc_msgSend2: 对消息接受者（id self, sel _cmd） 判断处理3：taggedPointer判断处理4：‘GetClassFromlsa_p16 isa’ 指针处理 - class5：CacheLoopup 查找缓存6：‘cache_t’ 处理 ’bucket’ 以及内存哈希处理   6.1: 找不到递归下一个 ‘bucket’   6.2: 找到了就返回 ‘{imp, sel} &#x3D; *bucket -&gt; imp’   6.3: 遇到意外就重试   6.4: 找不到就 ‘JumpMiss’7：__objc_msgSend_uncached 告诉找不到缓存 ‘imp’8：‘STATIC_ENTRY __objc_msgSend_uncached’9：‘MethodTableLookup’ 方法表查找   9.1: ‘sava parameter registers’   9.2: ‘self’ 以及 _cmd 准备   9.3: ‘_class_lookupMethodAndLoadCache3’ 调用
下面展示两种用法：
int main(int argc, char * argv[]) &#123;    @autoreleasepool &#123;               FLYStudent * person = [FLYStudent alloc];        objc_msgSend(person, sel_registerName(&quot;walk&quot;));                //调用对象方法        struct objc_super flySuper;        flySuper.receiver    = person;        flySuper.super_class = [person class];//receiver的isa        objc_msgSendSuper(&amp;flySuper, sel_registerName(&quot;walk&quot;));                //调用类方法        struct objc_super classSuper;        classSuper.receiver    = [person class];        classSuper.super_class = object_getClass([person class]);//receiver的isa（或者为receiver的isa的superClass）        objc_msgSendSuper(&amp;classSuper, sel_registerName(&quot;sayXiXi&quot;));    &#125;    return 0;&#125;

IMP _class_lookupMethodAndLoadCache3(id obj, SEL sel, Class cls)&#123;    return lookUpImpOrForward(cls, sel, obj,                               YES/*initialize*/, NO/*cache*/, YES/*resolver*/);&#125;
/************************************************************************ lookUpImpOrForward.* The standard IMP lookup. * initialize==NO tries to avoid +initialize (but sometimes fails)* cache==NO skips optimistic unlocked lookup (but uses cache elsewhere)* Most callers should use initialize==YES and cache==YES.* inst is an instance of cls or a subclass thereof, or nil if none is known. *   If cls is an un-initialized metaclass then a non-nil inst is faster.* May return _objc_msgForward_impcache. IMPs destined for external use *   must be converted to _objc_msgForward or _objc_msgForward_stret.*   If you don&#x27;t want forwarding at all, use lookUpImpOrNil() instead.**********************************************************************/IMP lookUpImpOrForward(Class cls, SEL sel, id inst,                        bool initialize, bool cache, bool resolver)&#123;    IMP imp = nil;    bool triedResolver = NO;    runtimeLock.assertUnlocked();    // Optimistic cache lookup    if (cache) &#123;        imp = cache_getImp(cls, sel);        if (imp) return imp;    &#125;    // runtimeLock is held during isRealized and isInitialized checking    // to prevent races against concurrent realization.    // runtimeLock is held during method search to make    // method-lookup + cache-fill atomic with respect to method addition.    // Otherwise, a category could be added but ignored indefinitely because    // the cache was re-filled with the old value after the cache flush on    // behalf of the category.    runtimeLock.lock();    checkIsKnownClass(cls);//检查是否是已知类    /**    如果没有初始化，去初始化该类    */    if (!cls-&gt;isRealized()) &#123;        realizeClass(cls);    &#125;    /**    initialize该类    */    if (initialize  &amp;&amp;  !cls-&gt;isInitialized()) &#123;        runtimeLock.unlock();        _class_initialize (_class_getNonMetaClass(cls, inst));        runtimeLock.lock();        // If sel == initialize, _class_initialize will send +initialize and         // then the messenger will send +initialize again after this         // procedure finishes. Of course, if this is not being called         // from the messenger then it won&#x27;t happen. 2778172    &#125;     retry:        runtimeLock.assertLocked();    // Try this class&#x27;s cache.    /**    取缓存，以下为汇编源码，防止被hook，以及运行速度和性能    STATIC_ENTRY _cache_getImp    GetClassFromIsa_p16 p0    CacheLookup GETIMP    LGetImpMiss:    mov p0, #0    ret    END_ENTRY _cache_getImp    */    imp = cache_getImp(cls, sel);    if (imp) goto done;    /**    查找当前类里面方法列表    */    // Try this class&#x27;s method lists.    &#123;        Method meth = getMethodNoSuper_nolock(cls, sel);        if (meth) &#123;            log_and_fill_cache(cls, meth-&gt;imp, sel, inst, cls);            imp = meth-&gt;imp;            goto done;        &#125;    &#125;    /**    查找父类里面方法    */    // Try superclass caches and method lists.    &#123;        unsigned attempts = unreasonableClassCount();        for (Class curClass = cls-&gt;superclass;             curClass != nil;             curClass = curClass-&gt;superclass)        &#123;            // Halt if there is a cycle in the superclass chain.            if (--attempts == 0) &#123;                _objc_fatal(&quot;Memory corruption in class list.&quot;);            &#125;                        // Superclass cache.            imp = cache_getImp(curClass, sel);            if (imp) &#123;                if (imp != (IMP)_objc_msgForward_impcache) &#123;                    // Found the method in a superclass. Cache it in this class.                    log_and_fill_cache(cls, imp, sel, inst, curClass);                    goto done;                &#125;                else &#123;                    // Found a forward:: entry in a superclass.                    // Stop searching, but don&#x27;t cache yet; call method                     // resolver for this class first.                    break;                &#125;            &#125;                        // Superclass method list.            Method meth = getMethodNoSuper_nolock(curClass, sel);            if (meth) &#123;                log_and_fill_cache(cls, meth-&gt;imp, sel, inst, curClass);                imp = meth-&gt;imp;                goto done;            &#125;        &#125;    &#125;    /**    消息转发机制    */    // No implementation found. Try method resolver once.    if (resolver  &amp;&amp;  !triedResolver) &#123;        runtimeLock.unlock();        _class_resolveMethod(cls, sel, inst);        runtimeLock.lock();        // Don&#x27;t cache the result; we don&#x27;t hold the lock so it may have         // changed already. Re-do the search from scratch instead.        triedResolver = YES;        goto retry;    &#125;    // No implementation found, and method resolver didn&#x27;t help.     // Use forwarding.    /**    最终都没有找到，走_objc_msgForward_impcache方法，苹果留的最后的后门，    汇编源码：    STATIC_ENTRY __objc_msgForward_impcache    // No stret specialization.    b   __objc_msgForward    END_ENTRY __objc_msgForward_impcache    ENTRY __objc_msgForward    adrp    x17, __objc_forward_handler@PAGE    ldr p17, [x17, __objc_forward_handler@PAGEOFF]    TailCallFunctionPointer x17        END_ENTRY __objc_msgForward    以上__objc_forward_handler是非汇编    */    imp = (IMP)_objc_msgForward_impcache;    cache_fill(cls, sel, imp, inst); done:    runtimeLock.unlock();    return imp;&#125;

__attribute__((noreturn)) void objc_defaultForwardHandler(id self, SEL sel)&#123;    _objc_fatal(&quot;%c[%s %s]: unrecognized selector sent to instance %p &quot;                &quot;(no message forward handler is installed)&quot;,                 class_isMetaClass(object_getClass(self)) ? &#x27;+&#x27; : &#x27;-&#x27;,                 object_getClassName(self), sel_getName(sel), self);&#125;void *_objc_forward_handler = (void*)objc_defaultForwardHandler;

void _class_resolveMethod(Class cls, SEL sel, id inst)&#123;    if (! cls-&gt;isMetaClass()) &#123;        // try [cls resolveInstanceMethod:sel]        _class_resolveInstanceMethod(cls, sel, inst);    &#125;     else &#123;        // try [nonMetaClass resolveClassMethod:sel]        // and [cls resolveInstanceMethod:sel]        _class_resolveClassMethod(cls, sel, inst);        if (!lookUpImpOrNil(cls, sel, inst,                             NO/*initialize*/, YES/*cache*/, NO/*resolver*/))         &#123;            _class_resolveInstanceMethod(cls, sel, inst);        &#125;    &#125;&#125;

static void _class_resolveInstanceMethod(Class cls, SEL sel, id inst)&#123;    if (! lookUpImpOrNil(cls-&gt;ISA(), SEL_resolveInstanceMethod, cls,                          NO/*initialize*/, YES/*cache*/, NO/*resolver*/))     &#123;        // Resolver not implemented.        return;    &#125;    BOOL (*msg)(Class, SEL, SEL) = (typeof(msg))objc_msgSend;    bool resolved = msg(cls, SEL_resolveInstanceMethod, sel);    // Cache the result (good or bad) so the resolver doesn&#x27;t fire next time.    // +resolveInstanceMethod adds to self a.k.a. cls    IMP imp = lookUpImpOrNil(cls, sel, inst,                              NO/*initialize*/, YES/*cache*/, NO/*resolver*/);    if (resolved  &amp;&amp;  PrintResolving) &#123;        if (imp) &#123;            _objc_inform(&quot;RESOLVE: method %c[%s %s] &quot;                         &quot;dynamically resolved to %p&quot;,                          cls-&gt;isMetaClass() ? &#x27;+&#x27; : &#x27;-&#x27;,                          cls-&gt;nameForLogging(), sel_getName(sel), imp);        &#125;        else &#123;            // Method resolver didn&#x27;t add anything?            _objc_inform(&quot;RESOLVE: +[%s resolveInstanceMethod:%s] returned YES&quot;                         &quot;, but no new implementation of %c[%s %s] was found&quot;,                         cls-&gt;nameForLogging(), sel_getName(sel),                          cls-&gt;isMetaClass() ? &#x27;+&#x27; : &#x27;-&#x27;,                          cls-&gt;nameForLogging(), sel_getName(sel));        &#125;    &#125;&#125;

static void _class_resolveClassMethod(Class cls, SEL sel, id inst)&#123;    assert(cls-&gt;isMetaClass());    if (! lookUpImpOrNil(cls, SEL_resolveClassMethod, inst,                          NO/*initialize*/, YES/*cache*/, NO/*resolver*/))     &#123;        // Resolver not implemented.        return;    &#125;    BOOL (*msg)(Class, SEL, SEL) = (typeof(msg))objc_msgSend;    bool resolved = msg(_class_getNonMetaClass(cls, inst),                         SEL_resolveClassMethod, sel);    // Cache the result (good or bad) so the resolver doesn&#x27;t fire next time.    // +resolveClassMethod adds to self-&gt;ISA() a.k.a. cls    IMP imp = lookUpImpOrNil(cls, sel, inst,                              NO/*initialize*/, YES/*cache*/, NO/*resolver*/);    if (resolved  &amp;&amp;  PrintResolving) &#123;        if (imp) &#123;            _objc_inform(&quot;RESOLVE: method %c[%s %s] &quot;                         &quot;dynamically resolved to %p&quot;,                          cls-&gt;isMetaClass() ? &#x27;+&#x27; : &#x27;-&#x27;,                          cls-&gt;nameForLogging(), sel_getName(sel), imp);        &#125;        else &#123;            // Method resolver didn&#x27;t add anything?            _objc_inform(&quot;RESOLVE: +[%s resolveClassMethod:%s] returned YES&quot;                         &quot;, but no new implementation of %c[%s %s] was found&quot;,                         cls-&gt;nameForLogging(), sel_getName(sel),                          cls-&gt;isMetaClass() ? &#x27;+&#x27; : &#x27;-&#x27;,                          cls-&gt;nameForLogging(), sel_getName(sel));        &#125;    &#125;&#125;

一、重写drawRect方法 - (void)drawRect:(CGRect)rect&#123; 	[super drawRect:rect];	 CGContextRef currentContext = UIGraphicsGetCurrentContext(); 	 //设置虚线颜色 	 CGContextSetStrokeColorWithColor(currentContext, [UIColor BlackColor].CGColor); 	 //设置虚线宽度 	 CGContextSetLineWidth(currentContext, 1); 	 //设置虚线绘制起点 	 CGContextMoveToPoint(currentContext, 0, 0); 	 //设置虚线绘制终点 	 CGContextAddLineToPoint(currentContext, self.frame.origin.x + self.frame.size.width, 0); //设置虚线排列的宽度间隔:下面的arr中的数字表示先绘制3个点再绘制1个点 	 CGFloat arr[] = &#123;3,1&#125;; 	 //下面最后一个参数“2”代表排列的个数。 	 CGContextSetLineDash(currentContext, 0, arr, 2); 	 CGContextDrawPath(currentContext, kCGPathStroke); &#125;
看着这些代码肯定有一部分人头疼，因为一般开发绘图部分用的比较少，特别是很少接触这些东西的人，甚至对绘图这部分的只是已经忘光了，所以在这里自己也脑补一下。以下来自转载iOS的绘图操作是在UIView类的drawRect方法中完成的，所以如果我们要想在一个UIView中绘图，需要写一个扩展UIView 的类，并重写drawRect方法，在这里进行绘图操作，程序会自动调用此方法进行绘图。下面先说明一下绘图，比如，你想绘制一个方块，你需要写一个类来扩展UIView并在drawRect方法中填入如下代码：
- (void)drawRect:(CGRect)rect &#123; 	// Drawing code. 	//获得处理的上下文 	CGContextRef context = UIGraphicsGetCurrentContext(); 	//设置线条样式 	CGContextSetLineCap(context, kCGLineCapSquare); 	//设置线条粗细宽度 	CGContextSetLineWidth(context, 1.0); 	//设置颜色 	CGContextSetRGBStrokeColor(context, 1.0, 0.0, 0.0, 1.0); 	//开始一个起始路径 	CGContextBeginPath(context); 	//起始点设置为(0,0):注意这是上下文对应区域中的相对坐标 	CGContextMoveToPoint(context, 0, 0); 	//设置下一个坐标点 	CGContextAddLineToPoint(context, 100, 100); 	/设置下一个坐标点 	CGContextAddLineToPoint(context, 0, 150); 	//设置下一个坐标点 CGContextAddLineToPoint(context, 50, 180); 	//连接上面定义的坐标点 	CGContextStrokePath(context); &#125;
再说明一下重绘，重绘操作仍然在drawRect方法中完成，但是苹果不建议直接调用drawRect方法，当然如果你强行直接调用此方法，当然是没有效果的。苹果要求我们调用UIView类中的setNeedsDisplay方法，则程序会自动调用drawRect方法进行重绘（调用setNeedsDisplay会自动调用drawRect）。在UIView中,重写drawRect: (CGRect)aRect方法,可以自己定义想要画的图案.且此方法一般情况下只会画一次.也就是说这个drawRect方法一般情况下只会被掉用一次。当某些情况下想要手动重画这个View,只需要掉用**[self setNeedsDisplay]**方法即可.drawRect的执行顺序及注意drawRect调是在Controller-&gt;loadView, Controller-&gt;viewDidLoad 两方法之后掉用的.如果在UIView初始化时没有设置rect大小，将直接导致drawRect不被自动调用。该方法在调用sizeThatFits后被调用，所以可以先调用sizeToFit计算出size。然后系统自动调用drawRect:方法。通过设置contentMode属性值为UIViewContentModeRedraw。那么将在每次设置或更改frame的时候自动调用drawRect:。直接调用setNeedsDisplay，或者setNeedsDisplayInRect:触发drawRect:，但是有个前提条件是rect不能为0.

以上1,2推荐；而3,4不提倡若使用UIView绘图，只能在drawRect：方法中获取相应的contextRef并绘图。如果在其他方法中获取将获取到一个invalidate的ref并且不能用于画图。drawRect：方法不能手动显示调用，必须通过调用setNeedsDisplay 或者 setNeedsDisplayInRect ，让系统自动调该方法。若使用calayer绘图，只能在drawInContext:中（类似鱼drawRect）绘制，或者在delegate中的相应方法绘制。同样也是调用setNeedDisplay等间接调用以上方法。若要实时画图，不能使用gestureRecognizer，只能使用touchbegan等方法来掉用setNeedsDisplay实时刷新屏幕转载地址：http://blog.csdn.net/fww330666557/article/details/8647608

二、通过UIImage的绘图方法来绘制&#x2F;&#x2F; 画虚线&#x2F;&#x2F; 创建一个imageView 高度是你想要的虚线的高度 一般设为2_lineImg &#x3D; [[UIImageView alloc] initWithFrame:CGRectMake(0, 20, kScreenWidth, 2)];&#x2F;&#x2F; 调用方法 返回的iamge就是虚线_lineImg.image &#x3D; [self drawLineByImageView:_lineImg];&#x2F;&#x2F; 添加到控制器的view上[self.view addSubview:_lineImg];&#x2F;&#x2F; 返回虚线image的方法
- (UIImage *)drawLineByImageView:(UIImageView *)imageView&#123; 	UIGraphicsBeginImageContext(imageView.frame.size);	//开始画线 划线的frame 	[imageView.image drawInRect:CGRectMake(0, 0, imageView.frame.size.width, imageView.frame.size.height)]; 	//设置线条终点形状 	CGContextSetLineCap(UIGraphicsGetCurrentContext(), kCGLineCapRound); 	// 5是每个虚线的长度 1是高度 	float lengths[] = &#123;5,1&#125;; 	CGContextRef line = UIGraphicsGetCurrentContext(); 	// 设置颜色 	CGContextSetStrokeColorWithColor(line, [UIColor colorWithWhite:0.408 alpha:1.000].CGColor); 	CGContextSetLineDash(line, 0, lengths, 2); 	//画虚线 	CGContextMoveToPoint(line, 0.0, 2.0); 	//开始画线 CGContextAddLineToPoint(line, kScreenWidth - 10, 2.0); 	CGContextStrokePath(line);	UIGraphicsGetImageFromCurrentImageContext()	//返回的就是image	return UIGraphicsGetImageFromCurrentImageContext(); &#125;
三、通过CAShapeLayer方式绘制虚线/** ** lineView: 需要绘制成虚线的view ** lineLength: 虚线的宽度 ** lineSpacing: 虚线的间距 ** lineColor: 虚线的颜色 **/+ (void)drawDashLine:(UIView *)lineView lineLength:(int)lineLength lineSpacing:(int)lineSpacing lineColor:(UIColor *)lineColor&#123; 	CAShapeLayer *shapeLayer = [CAShapeLayer layer]; 	[shapeLayer setBounds:lineView.bounds]; 	[shapeLayer setPosition:CGPointMake(CGRectGetWidth(lineView.frame) / 2, CGRectGetHeight(lineView.frame))];	[shapeLayer setFillColor:[UIColor clearColor].CGColor]; 	// 设置虚线颜色为blackColor 	[shapeLayer setStrokeColor:lineColor.CGColor]; 	// 设置虚线宽度 	[shapeLayer setLineWidth:CGRectGetHeight(lineView.frame)]; 	[shapeLayer setLineJoin:kCALineJoinRound]; 	// 设置线宽，线间距 	[shapeLayer setLineDashPattern:[NSArray arrayWithObjects:[NSNumber numberWithInt:lineLength], [NSNumber numberWithInt:lineSpacing], nil]]; 	// 设置路径 CGMutablePathRef path = CGPathCreateMutable(); CGPathMoveToPoint(path, NULL, 0, 0);	CGPathAddLineToPoint(path, NULL,CGRectGetWidth(lineView.frame), 0); 	[shapeLayer setPath:path]; CGPathRelease(path); 	// 把绘制好的虚线添加上来 	[lineView.layer addSublayer:shapeLayer]; &#125;
