2.5、关键字 - Main Dispatch Queue&#x2F;Global Dispatch Queue实际上不用特意生成Dispatch Queue，系统也会为我们准备几个。那就是Main Dispatch Queue和Global Dispatch Queue。

Main Dispatch Queue就是主线程，因为主线程只有一个，所以Main Dispatch Queue是Serial Dispatch Queue。Main Dispatch Queue的处理在主线程的Runloop中执行。

相应的，Global Dispatch Queue是系统为我们准备的Concurrent Dispatch Queue。Global Dispatch Queue有四个优先级，应根据需求使用对应优先级。

 /**  high优先级的获取方法 */dispatch_queue_t globalHighQueue = dispatch_get_global_queue(DISPATCH_QUEUE_PRIORITY_HIGH, 0); /**  default优先级的获取方法 */dispatch_queue_t globalDefaultQueue = dispatch_get_global_queue(DISPATCH_QUEUE_PRIORITY_DEFAULT, 0); /**  low优先级的获取方法 */dispatch_queue_t globalLowQueue = dispatch_get_global_queue(DISPATCH_QUEUE_PRIORITY_LOW, 0); /**  background优先级的获取方法 */dispatch_queue_t globalBackgroundQueue = dispatch_get_global_queue(DISPATCH_QUEUE_PRIORITY_BACKGROUND, 0);
更改队列优先级：dispatch_set_target_queue(dispatch_object_t  _Nonnull object, dispatch_queue_t  _Nullable queue)
dispatch_queue_t serialQueue = dispatch_queue_create(&quot;aa&quot;, DISPATCH_QUEUE_SERIAL);//串行队列   dispatch_queue_t globalBackgroundQueue = dispatch_get_global_queue(DISPATCH_QUEUE_PRIORITY_BACKGROUND, 0);   dispatch_set_target_queue(serialQueue, globalBackgroundQueue);将serialQueue指定为globalBackgroundQueue用。
注：如果这里用函数dispatch_set_target_queue将多个Serial Dispatch Queue指定为同一个Serial Dispatch Queue，就会将原本并发的队列变更为串行队列。
2.6、关键字 - Dispatch Group/**将原本在serialQueue中要执行的放在group里，后面可以加一个结束的回调（很多时候会有这种需求）*/    dispatch_group_t group = dispatch_group_create();    dispatch_group_async(group, serialQueue, ^&#123;        //代码    &#125;);    dispatch_group_async(group, serialQueue, ^&#123;        //代码    &#125;);    dispatch_group_async(group, serialQueue, ^&#123;        //代码    &#125;);    dispatch_group_notify(group, dispatch_get_main_queue(), ^&#123;        NSLog(@&quot;done&quot;);//执行完成后回调    &#125;);
2.7、关键字 - dispatch_barrier_async 栅栏dispatch_queue_t concurrentQueue = dispatch_queue_create(&quot;abcd&quot;, DISPATCH_QUEUE_CONCURRENT);//并行队列   dispatch_async(concurrentQueue, ^&#123;       [self loadImage:@0];       //读取数据0   &#125;);   dispatch_async(concurrentQueue, ^&#123;       [self loadImage:@1];       //读取数据1   &#125;);   dispatch_async(concurrentQueue, ^&#123;       [self loadImage:@2];       //读取数据2   &#125;);   dispatch_async(concurrentQueue, ^&#123;       [self loadImage:@3];       //读取数据3   &#125;);   dispatch_barrier_async(concurrentQueue, ^&#123;       [self loadImage:@4];      //异步栅栏写入数据4   &#125;);   dispatch_barrier_sync(concurrentQueue, ^&#123;       [self loadImage:@4];       //同步栅栏写入数据4   &#125;);   dispatch_async(concurrentQueue, ^&#123;       [self loadImage:@5];       //读取数据5   &#125;);   dispatch_async(concurrentQueue, ^&#123;       [self loadImage:@6];       //读取数据6   &#125;);   dispatch_async(concurrentQueue, ^&#123;       [self loadImage:@7];       //读取数据7   &#125;);   dispatch_async(concurrentQueue, ^&#123;       [self loadImage:@8];       //读取数据8   &#125;);
