二、简单的情况，JS中点击事件直接调用方法方式2.1 JS代码如下：&lt;!DOCTYPE html&gt;&lt;html&gt;    &lt;meta http-equiv=&quot;Content-Type&quot; content=&quot;text/html; charset=utf-8&quot; /&gt;    &lt;meta content=&quot;width=device-width,initial-scale=1,user-scalable=no&quot; name=&quot;viewport&quot;&gt;&lt;body style=&quot;background-color: white;&quot;&gt;    &lt;script type=&quot;text/javascript&quot;&gt;        var nativeCallJS = function(parameter) &#123;            alert (parameter);        &#125;;    &lt;/script&gt;    &lt;button type=&quot;button&quot; onclick = &quot;jsCallNative(&#x27;jsParameter&#x27;)&quot; style=&quot;width:100%; height:30px;&quot;/&gt;调用OC代码&lt;/button&gt;&lt;/body&gt;&lt;/html&gt;
2.2 oc代码如下：- (void)doSomeJsThings&#123;        self.jsContext = [_webView valueForKeyPath:@&quot;documentView.webView.mainFrame.javaScriptContext&quot;];    self.jsContext.exceptionHandler = ^(JSContext *context, JSValue *exception) &#123;        NSLog(@&quot;出现异常，异常信息：%@&quot;,exception);    &#125;;        //oc调用js    JSValue * nativeCallJS = self.jsContext[@&quot;nativeCallJS&quot;];    [nativeCallJS callWithArguments:@[@&quot;hello word&quot;]];//调用了js中方法&quot;nativeCallJS&quot;,并且传参数@&quot;hello word&quot;        //在本地生成js方法，供js调用    self.jsContext[@&quot;jsCallNative&quot;] = ^(NSString *paramer)&#123;        JSValue *currentThis = [JSContext currentThis];        JSValue *currentCallee = [JSContext currentCallee];        NSArray *currentParamers = [JSContext currentArguments];        dispatch_async(dispatch_get_main_queue(), ^&#123;            /**             *  js调起OC代码，代码在子线程，更新OC中的UI，需要回到主线程             */            NSLog(@&quot;js传过来：%@&quot;,paramer);        &#125;);        NSLog(@&quot;JS paramer is %@&quot;,paramer);        NSLog(@&quot;currentThis is %@&quot;,[currentThis toString]);        NSLog(@&quot;currentCallee is %@&quot;,[currentCallee toString]);        NSLog(@&quot;currentParamers is %@&quot;,currentParamers);    &#125;;//生成native的js方法，方法名：@&quot;jsCallNative&quot;,js可直接调用此方法&#125;
