以上就是简单的调用。
三、复杂调用，JS中，点击事件等事件通过调用全局对象的方法调用方法，JS和Native代码的互调如下：3.1 JS代码如下：&lt;!DOCTYPE html&gt;&lt;html&gt;    &lt;meta http-equiv=&quot;Content-Type&quot; content=&quot;text/html; charset=utf-8&quot; /&gt;    &lt;meta content=&quot;width=device-width,initial-scale=1,user-scalable=no&quot; name=&quot;viewport&quot;&gt;&lt;body style=&quot;background-color: white;&quot;&gt;    &lt;script type=&quot;text/javascript&quot;&gt;        globalObject = new Object();        globalObject.name = 100;        globalObject.nativeCallJS = function (parameter) &#123;            alert (parameter);        &#125;;    &lt;/script&gt;        &lt;button type=&quot;button&quot; onclick = &quot;NativeObject.jsCallNative()&quot; style=&quot;width:100%; height:30px;&quot;/&gt;调用OC代码&lt;/button&gt;    &lt;button type=&quot;button&quot; onclick = &quot;NativeObject.shareString(&#x27;jsParameter&#x27;)&quot; style=&quot;width:100%; height:30px;&quot;/&gt;调用OC代码并传参数&lt;/button&gt;&lt;/body&gt;&lt;/html&gt;
3.2 oc代码如下：//声明的协议，当前viewController必须遵守@protocol JSObjcDelegate &lt;JSExport&gt;- (void)jsCallNative;- (void)shareString:(NSString *)shareString;@end//方法实现，在webViewDidFinishLoad中调用- (void)doSomeJsThings&#123;        self.jsContext = [_webView valueForKeyPath:@&quot;documentView.webView.mainFrame.javaScriptContext&quot;];    self.jsContext.exceptionHandler = ^(JSContext *context, JSValue *exception) &#123;        NSLog(@&quot;出现异常，异常信息：%@&quot;,exception);    &#125;;        //oc调用js    JSValue * jsObj = self.jsContext[@&quot;globalObject&quot;];//拿到js中要调用方法的全局对象    //jsObj执行其方法nativeCallJS    JSValue * returnValue = [jsObj invokeMethod:@&quot;nativeCallJS&quot; withArguments:@[@&quot;hello word&quot;]];   //调用了js中方法&quot;nativeCallJS&quot;,并且传参数@&quot;hello word&quot;,这里returnValue是调用之后的返回值，可能为nil    NSLog(@&quot;returnValue:%@&quot;,returnValue);        //写法1    JSValue * jsCallNative = [JSValue valueWithObject:self inContext:self.jsContext];//此方法会转换self为JS对象，但是self中必须实现指定的方法和协议    self.jsContext[@&quot;NativeObject&quot;] = jsCallNative;    //写法2    //self.jsContext[@&quot;NativeObject&quot;] = self;    //注：写法1和写法2效果相同，推荐写法1，毕竟系统方法&#125;- (void)jsCallNative&#123;//在本地生成js方法，供js调用        JSValue *currentThis = [JSContext currentThis];    JSValue *currentCallee = [JSContext currentCallee];    NSArray *currentParamers = [JSContext currentArguments];    dispatch_async(dispatch_get_main_queue(), ^&#123;        /**         *  js调起OC代码，代码在子线程，更新OC中的UI，需要回到主线程         */    &#125;);    NSLog(@&quot;currentThis is %@&quot;,[currentThis toString]);    NSLog(@&quot;currentCallee is %@&quot;,[currentCallee toString]);    NSLog(@&quot;currentParamers is %@&quot;,currentParamers);    &#125;- (void)shareString:(NSString *)shareString&#123;//在本地生成js方法，供js调用        JSValue *currentThis = [JSContext currentThis];    JSValue *currentCallee = [JSContext currentCallee];    NSArray *currentParamers = [JSContext currentArguments];    dispatch_async(dispatch_get_main_queue(), ^&#123;        /**         *  js调起OC代码，代码在子线程，更新OC中的UI，需要回到主线程         */        NSLog(@&quot;js传过来：%@&quot;,shareString);    &#125;);    NSLog(@&quot;JS paramer is %@&quot;,shareString);    NSLog(@&quot;currentThis is %@&quot;,[currentThis toString]);    NSLog(@&quot;currentCallee is %@&quot;,[currentCallee toString]);    NSLog(@&quot;currentParamers is %@&quot;,currentParamers);&#125;
